#define spacer(c) (c <= ' ' || c == '(' || c == ')')
#define chex(c) (0xf & (c - (c <= '9' ? '0' : 0x57)))

static char *copy(char *src, char *dst, int length)
{
	while (length--)
		*dst++ = *src++;
	return dst;
}

static char *walk(char *s)
{
	char c;
	int depth = 0;
	if (*s == '(') {
		while ((c = *s++)) {
			if (c == '(')
				depth++;
			if (c == ')')
				--depth;
			if (!depth)
				return s;
		}
	}
	while ((c = *s) && !spacer(c))
		s++;
	return s;
}

static int sint(char *s)
{
	char c = *s, *cap = walk(s);
	int r = 0, n = 1;
	if (c == '#') {
		s++;
		while ((c = *s) && s++ < cap)
			r = (r << 4) | chex(c);
		return r;
	}
	if (c == '-') {
		n = -1;
		s++;
	}
	while ((c = *s) && s++ < cap)
		r = r * 10 + c - '0';
	return r * n;
}

static void device_write(char *s)
{
	char **reg = regs + '0';
	if (!*reg)
		return;
	int hex = **reg == '#', acc = sint(*reg++);
