	/* clang-format on */
	dst_ += snprintf(dst_, 0x10, hex ? \"#%x\" : \"%d\", acc);
}

static void write_reg(char r, char *reg)
{
	unsigned char c;
	char *cap;
	switch(r) {
	case ':':
		device_write(reg);
		return;
	case '^': /* op: join */
