		cap = walk(reg);
		if (*reg == '(' && reg[1] != ')') { /* tuple */
			reg++;
			while (reg < cap - 1) {
				while ((c = *reg) && !spacer(c))
					*dst_++ = c, reg++;
				*dst_++ = ' ', *dst_++ = '(', reg++, depth++;
			}
		} else /* token */
			while ((c = *reg++) && !spacer(c))
				*dst_++ = c, *dst_++ = ' ', *dst_++ = '(', depth++;
		for (i = 0; i < depth; i++) *dst_++ = ')';
		return;
	default:
		dst_ = copy(reg, dst_, walk(reg) - reg);
		return;
	}
