static int write_tail(char *s, rule *r)
{
	while ((*dst_++ = *s++));
	*dst_ = 0;
	if ((flip = !flip))
		src_ = bank_b, dst_ = bank_a;
	else
		src_ = bank_a, dst_ = bank_b;
	return 1;
}

static int apply_rule(rule *r, char *s)
{
	unsigned char rid;
	char c, *a = r->a, *b = r->b, *origin = dst_, *reg;
	/* phase: clean regs */
	while (stack_ != stack)
		regs[(int)*(--stack_)] = 0;
	/* phase: match rule */
	while ((c = *a++)) {
		if (c == '?') {
			char *pcap = walk(s);
			if (pcap == s)
				return 0;
			rid = *a++;
			if ((reg = regs[rid])) { /* reg cmp */
				char *rcap = walk(reg), *pp = s;
				if (rcap - reg != pcap - pp)
					return 0;
				while (reg < rcap)
					if (*reg++ != *pp++)
						return 0;
			} else /* reg set */
				regs[rid] = s, *stack_++ = rid;
			s = pcap;
		} else if (c != *s++)
			return 0;
	}
	c = *s;
	if (!spacer(c))
		return 0;
